diff --git a/llvm/lib/IR/BasicBlock.cpp b/llvm/lib/IR/BasicBlock.cpp
index 39cefa5280c6..790e2817472e 100644
--- a/llvm/lib/IR/BasicBlock.cpp
+++ b/llvm/lib/IR/BasicBlock.cpp
@@ -579,7 +579,10 @@ BasicBlock *BasicBlock::splitBasicBlock(iterator I, const Twine &BBName,
   if (Before)
     return splitBasicBlockBefore(I, BBName);

-  assert(getTerminator() && "Can't use splitBasicBlock on degenerate BB!");
+  if (!getTerminator()) {
+    llvm::errs() << "Error: Attempting to split a degenerate basic block without a terminator.\n";
+    return nullptr;
+}
   assert(I != InstList.end() &&
          "Trying to get me to create degenerate basic block!");

